    <input type="text" placeholder="Search tasks by title..."
           value="@SearchText"
           @oninput="OnInput" />
</div>

@code {
    [Parameter] public string SearchText { get; set; } = string.Empty;
    [Parameter] public EventCallback<string> SearchTextChanged { get; set; }

    private async Task OnInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? string.Empty;
        await SearchTextChanged.InvokeAsync(value);
    }
}
"}

{"path": "/tmp/sv-1dac147255c04024a15ed81c9d6685d1/Components/Board/BoardColumn.razor", "file_text": "<div class="board-column">
    <div class="column-header">
        <h3>@Title (@Tasks.Count)</h3>
    </div>

    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="ShowMoveLeft"
                      ShowMoveRight="ShowMoveRight"
                      OnMoveLeft="HandleMoveLeft"
                      OnMoveRight="HandleMoveRight" />
        }
    </div>

    <div class="column-footer">
        <AddTaskForm ColumnStatus="@Status" OnTaskCreated="HandleTaskCreated" />
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string Title { get; set; } = default!;
    [Parameter, EditorRequired] public string Status { get; set; } = default!;
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool ShowMoveLeft { get; set; }
    [Parameter] public bool ShowMoveRight { get; set; }
    [Parameter] public string? LeftStatus { get; set; }
    [Parameter] public string? RightStatus { get; set; }
    [Parameter] public EventCallback<(int TaskId, string NewStatus)> OnTaskMoved { get; set; }
    [Parameter] public EventCallback<TaskItem> OnTaskCreated { get; set; }

    private async Task HandleMoveLeft(int taskId)
    {
        if (LeftStatus is not null)
            await OnTaskMoved.InvokeAsync((taskId, LeftStatus));
    }

    private async Task HandleMoveRight(int taskId)
    {
        if (RightStatus is not null)
            await OnTaskMoved.InvokeAsync((taskId, RightStatus));
    }

    private async Task HandleTaskCreated(TaskItem task)
    {
        await OnTaskCreated.InvokeAsync(task);
    }
}
"}

