arguments.file_text:
@page "/board"
@using sv_1dac147255c04024a15ed81c9d6685d1.Components.Board
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h2>Project Board</h2>

@if (isLoading)
{
    <p class="board-loading">Loading tasks…</p>
}
else if (errorMessage is not null)
{
    <div class="board-error">
        <p>@errorMessage</p>
        <button @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Tasks="allTasks" />
    <BoardSearchBar @bind-SearchText="searchText" />

    <div class="board-columns">
        <BoardColumn Title="To Do" Status="To Do"
                     Tasks="GetFilteredTasks("To Do")"
                     ShowMoveLeft="false" ShowMoveRight="true"
                     RightStatus="In Progress"
                     OnTaskMoved="HandleTaskMoved"
                     OnTaskCreated="HandleTaskCreated" />

        <BoardColumn Title="In Progress" Status="In Progress"
                     Tasks="GetFilteredTasks("In Progress")"
                     ShowMoveLeft="true" ShowMoveRight="true"
                     LeftStatus="To Do" RightStatus="Done"
                     OnTaskMoved="HandleTaskMoved"
                     OnTaskCreated="HandleTaskCreated" />

        <BoardColumn Title="Done" Status="Done"
                     Tasks="GetFilteredTasks("Done")"
                     ShowMoveLeft="true" ShowMoveRight="false"
                     LeftStatus="In Progress"
                     OnTaskMoved="HandleTaskMoved"
                     OnTaskCreated="HandleTaskCreated" />
    </div>
}

@code {
    [Inject] private ITaskService TaskService { get; set; } = default!;

    private List<TaskItem> allTasks = new();
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;
        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var filtered = allTasks.Where(t => t.Status == status);

        if (!string.IsNullOrWhiteSpace(searchText))
        {
            filtered = filtered.Where(t =>
                t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }

        return filtered.ToList();
    }

    private async Task HandleTaskMoved((int TaskId, string NewStatus) move)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(move.TaskId, move.NewStatus);
            var index = allTasks.FindIndex(t => t.Id == move.TaskId);
            if (index >= 0)
            {
                var old = allTasks[index];
                allTasks[index] = old with { Status = move.NewStatus };
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private Task HandleTaskCreated(TaskItem task)
    {
        allTasks.Add(task);
        return Task.CompletedTask;
    }
}

/* --- Board Layout --- */
.board-columns {
    display: flex;
    gap: 1rem;
    align-items: flex-start;
}

.board-loading,
.board-error {
    padding: 2rem;
    text-align: center;
}

.board-error button {
    margin-top: 0.5rem;
    padding: 0.4rem 1rem;
    cursor: pointer;
}

/* --- Stats Bar --- */
.board-stats {
    display: flex;
    gap: 1.5rem;
    padding: 0.75rem 1rem;
    background: #f0f4f8;
    border-radius: 6px;
    margin-bottom: 1rem;
    flex-wrap: wrap;
}

.stat-item {
    display: flex;
    flex-direction: column;
    align-items: center;
}

.stat-label {
    font-size: 0.75rem;
    text-transform: uppercase;
    color: #666;
}

.stat-value {
    font-size: 1.25rem;
    font-weight: 700;
}

.stat-overdue .stat-value {
    color: #dc3545;
}

/* --- Search Bar --- */
.board-search {
    margin-bottom: 1rem;
}

.board-search input {
    width: 100%;
    max-width: 400px;
    padding: 0.5rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 0.9rem;
}

/* --- Column --- */
.board-column {
    flex: 1;
    min-width: 250px;
    background: #f7f8fa;
    border-radius: 8px;
    padding: 0.75rem;
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

.column-header h3 {
    margin: 0 0 0.25rem;
    font-size: 1rem;
}

.column-body {
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    min-height: 60px;
}

/* --- Task Card --- */
.task-card {
    background: #fff;
    border: 1px solid #e0e0e0;
    border-radius: 6px;
    padding: 0.75rem;
}

.task-title {
    margin: 0 0 0.25rem;
    font-size: 0.95rem;
}

.task-assignee {
    margin: 0 0 0.35rem;
    font-size: 0.8rem;
    color: #555;
}

.task-due-date {
    font-size: 0.8rem;
    color: #777;
    margin-left: 0.5rem;
}

.priority-badge {
    display: inline-block;
    padding: 0.15rem 0.5rem;
    border-radius: 3px;
    font-size: 0.75rem;
    font-weight: 600;
    color: #fff;
}

.priority-high {
    background-color: #dc3545;
}

.priority-medium {
    background-color: #ffc107;
    color: #333;
}

.priority-low {
    background-color: #28a745;
}

.task-actions {
    margin-top: 0.5rem;
    display: flex;
    gap: 0.5rem;
}

.btn-move {
    font-size: 0.75rem;
    padding: 0.25rem 0.5rem;
    border: 1px solid #ccc;
    background: #fff;
    border-radius: 4px;
    cursor: pointer;
}

.btn-move:hover {
    background: #e9ecef;
}

/* --- Add Task --- */
.btn-add-task {
    width: 100%;
    padding: 0.5rem;
    border: 1px dashed #aaa;
    background: transparent;
    border-radius: 4px;
    cursor: pointer;
    color: #555;
    font-size: 0.85rem;
}

.btn-add-task:hover {
    background: #eee;
}

.add-task-form {
    display: flex;
    flex-direction: column;
    gap: 0.4rem;
    padding: 0.5rem;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
}

.add-task-form input,
.add-task-form select {
    padding: 0.4rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 0.85rem;
}

.form-actions {
    display: flex;
    gap: 0.5rem;
}

.btn-save,
.btn-cancel {
    padding: 0.35rem 0.75rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    cursor: pointer;
    font-size: 0.8rem;
}

.btn-save {
    background: #0d6efd;
    color: #fff;
    border-color: #0d6efd;
}

.btn-save:disabled {
    opacity: 0.6;
    cursor: not-allowed;
}

.btn-cancel {
    background: #fff;
}

.form-error {
    color: #dc3545;
    font-size: 0.8rem;
    margin: 0;
}

